CREATE TABLE IF NOT EXISTS privacy_risk_findings(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,title text NOT NULL,control text NOT NULL,severity text NOT NULL CHECK(severity IN ('low','medium','high','critical')),status text NOT NULL DEFAULT 'open',owner text NOT NULL DEFAULT '',due_at timestamptz,remediation_plan text NOT NULL DEFAULT '',exception_reason text NOT NULL DEFAULT '',exception_expires_at timestamptz,approved_by text NOT NULL DEFAULT '',resolution_note text NOT NULL DEFAULT '',resolved_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_privacy_risk_due ON privacy_risk_findings(tenant_id,status,due_at); CREATE INDEX IF NOT EXISTS idx_privacy_risk_severity ON privacy_risk_findings(tenant_id,severity,status);
